import React, { useState, useEffect, useRef } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Separator } from '@/components/ui/separator';
import { Switch } from '@/components/ui/switch';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '@/components/ui/alert-dialog';
import { Edit, Save, X, Upload, Loader2, ImageIcon, ShieldCheck, Shield, MonitorSmartphone, FlaskConical } from 'lucide-react';
import { toast } from 'sonner';
import SearchableProfileField from './profile/SearchableProfileField';
import type { Database } from '@/integrations/supabase/types';
import { useUserRole } from '@/hooks/useUserRole';
import { useOrganisationContext } from '../context/OrganisationContext';
import debug from '../utils/debug';

type OrgSigRole = Database['public']['Tables']['org_sig_roles']['Row'];

interface Profile {
  id: string;
  full_name: string;
  email: string;
}

interface OrganisationData {
  id?: string;
  org_name?: string;
  org_short_name?: string;
  acra_uen_number?: string;
  charity_registration_number?: string;
  address?: string;
  telephone?: string;
  annual_turnover?: string;
  number_of_employees?: number;
  number_of_executives?: number;
  appointed_certification_body?: string;
  org_logo_url?: string;
  entra_enabled?: boolean;
  azure_tenant_id?: string;
  // Device management integration
  device_source?: string | null;
  intune_client_id?: string | null;
  intune_client_secret?: string | null;  // stores Vault secret name, not raw value
  atera_api_key?: string | null;         // stores Vault secret name, not raw value
  atera_customer_id?: number | null;
  device_last_synced_at?: string | null;
}


interface SignatoryData {
  name_signatory_cem?: string;
  title_signatory_cem?: string;
  email_signatory_cem?: string;
  name_signatory_hib?: string;
  title_signatory_hib?: string;
  email_signatory_hib?: string;
  name_signatory_dpe?: string;
  title_signatory_dpe?: string;
  email_signatory_dpe?: string;
  dpo_name?: string;
  dpo_email?: string;
  iso_name?: string;
  iso_email?: string;
  head_it_name?: string;
  head_it_email?: string;
  it_manager_name?: string;
  it_manager_email?: string;
}

const OrganisationProfile: React.FC = () => {
  const [isEditing, setIsEditing] = useState(false);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [uploadingLogo, setUploadingLogo] = useState(false);
  const [organisationData, setOrganisationData] = useState<OrganisationData>({});
  const [signatoryData, setSignatoryData] = useState<SignatoryData>({});
  const logoFileInputRef = useRef<HTMLInputElement>(null);
  const { isSuperAdmin, hasAdminAccess } = useUserRole();
  const { supabaseClient } = useOrganisationContext();
  debug.state('[OrganisationProfile] role flags', { isSuperAdmin, hasAdminAccess });

  // MFA policy toggle — saved immediately, independent of the edit/save flow
  const [requireMfa, setRequireMfa] = useState(false);
  const [mfaSaving, setMfaSaving] = useState(false);
  const [showDisableMfaConfirm, setShowDisableMfaConfirm] = useState(false);

  // Entra SSO toggle — saved immediately like MFA; azure_tenant_id saved via edit/save flow
  const [entraEnabled, setEntraEnabled] = useState(false);
  const [entraSaving, setEntraSaving] = useState(false);

  // Device management toggle — saved immediately; source + credentials saved via edit/save flow
  const [deviceEnabled, setDeviceEnabled] = useState(false);
  const [deviceSaving, setDeviceSaving] = useState(false);
  const [testingConnection, setTestingConnection] = useState(false);

  // Secret draft values — only written to Vault on save if changed from placeholder
  const SECRET_PLACEHOLDER = '••••••••';
  const [intuneSecretDraft, setIntuneSecretDraft] = useState('');
  const [ateraKeyDraft, setAteraKeyDraft] = useState('');

  // Detect Learn vs Govern context (same pattern as PersonaDetailsTabs)
  const isLearnMode = typeof window !== 'undefined' &&
    (window.location.hostname.includes('learn') || window.location.port.startsWith('80'));

  // Phone validation function
  const validatePhoneInput = (input: string): string => {
    return input.replace(/[^0-9+\s\-()]/g, '');
  };

  const handleTelephoneChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const validatedValue = validatePhoneInput(e.target.value);
    setOrganisationData(prev => ({ ...prev, telephone: validatedValue }));
  };
  const handleLogoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const validTypes = ['image/jpeg', 'image/png', 'image/gif', 'image/webp', 'image/svg+xml'];
    if (!validTypes.includes(file.type)) {
      toast.error('Please upload an image (JPEG, PNG, GIF, WebP, or SVG)');
      return;
    }
    if (file.size > 2 * 1024 * 1024) {
      toast.error('Logo must be smaller than 2 MB');
      return;
    }

    setUploadingLogo(true);
    try {
      const ext = file.name.split('.').pop();
      const storagePath = `org-logo/logo-${Date.now()}.${ext}`;

      const { error: uploadError } = await supabaseClient.storage
        .from('logos')
        .upload(storagePath, file, { contentType: file.type, upsert: true });

      if (uploadError) throw uploadError;

      const { data: urlData } = supabaseClient.storage
        .from('logos')
        .getPublicUrl(storagePath);

      setOrganisationData(prev => ({ ...prev, org_logo_url: urlData.publicUrl }));
      toast.success('Logo uploaded — click Save to apply');
    } catch (err: any) {
      console.error('Logo upload error:', err);
      toast.error('Failed to upload logo: ' + (err.message ?? 'unknown error'));
    } finally {
      setUploadingLogo(false);
      if (logoFileInputRef.current) logoFileInputRef.current.value = '';
    }
  };

  useEffect(() => {
    fetchOrganisationData();
  }, [supabaseClient]);

  useEffect(() => {
    debug.state('[OrganisationProfile] MFA toggle visibility', { hasAdminAccess, requireMfa, willShowToggle: hasAdminAccess });
  }, [hasAdminAccess, requireMfa]);

  const fetchOrganisationData = async () => {
    try {
      setLoading(true);
      
      // Fetch organisation profile data
      const { data: orgProfile, error: orgError } = await supabaseClient
        .from('org_profile')
        .select('*')
        .maybeSingle();

      if (orgError) {
        throw orgError;
      }

      if (orgProfile) {
        setOrganisationData(orgProfile);
        setRequireMfa(orgProfile.require_mfa ?? false);
        setEntraEnabled(orgProfile.entra_enabled ?? false);
        setDeviceEnabled(!!orgProfile.device_source);
        // Show placeholder for secrets if a Vault name is already stored
        setIntuneSecretDraft(orgProfile.intune_client_secret ? SECRET_PLACEHOLDER : '');
        setAteraKeyDraft(orgProfile.atera_api_key ? SECRET_PLACEHOLDER : '');
        debug.state('[OrganisationProfile] org_profile loaded', { require_mfa: orgProfile.require_mfa, entra_enabled: orgProfile.entra_enabled, device_source: orgProfile.device_source });
      }

      // Fetch signatory roles data
      const { data: sigRoles, error: sigError } = await supabaseClient
        .from('org_sig_roles')
        .select('*');

      if (sigError) {
        throw sigError;
      }

      if (sigRoles && sigRoles.length > 0) {
        const sigData: SignatoryData = {};
        
        sigRoles.forEach((role: OrgSigRole) => {
          switch (role.role_type) {
            case 'cem':
              sigData.name_signatory_cem = role.signatory_name;
              sigData.title_signatory_cem = role.signatory_title;
              sigData.email_signatory_cem = role.signatory_email;
              break;
            case 'hib':
              sigData.name_signatory_hib = role.signatory_name;
              sigData.title_signatory_hib = role.signatory_title;
              sigData.email_signatory_hib = role.signatory_email;
              break;
            case 'dpe':
              sigData.name_signatory_dpe = role.signatory_name;
              sigData.title_signatory_dpe = role.signatory_title;
              sigData.email_signatory_dpe = role.signatory_email;
              break;
            case 'dpo':
              sigData.dpo_name = role.signatory_name;
              sigData.dpo_email = role.signatory_email;
              break;
            case 'iso':
              sigData.iso_name = role.signatory_name;
              sigData.iso_email = role.signatory_email;
              break;
            case 'head_it':
              sigData.head_it_name = role.signatory_name;
              sigData.head_it_email = role.signatory_email;
              break;
            case 'it_manager':
              sigData.it_manager_name = role.signatory_name;
              sigData.it_manager_email = role.signatory_email;
              break;
          }
        });
        
        setSignatoryData(sigData);
      }

    } catch (error) {
      console.error('Error fetching organisation data:', error);
      toast.error('Failed to load organisation data');
    } finally {
      setLoading(false);
    }
  };

  const handleSave = async () => {
    try {
      setSaving(true);
      
      // Save organisation profile data
      const { error: orgError } = await supabaseClient
        .from('org_profile')
        .upsert(organisationData);

      if (orgError) throw orgError;

      // Update signatory roles data
      const updates = [
        { role_type: 'cem', signatory_name: signatoryData.name_signatory_cem, signatory_title: signatoryData.title_signatory_cem, signatory_email: signatoryData.email_signatory_cem },
        { role_type: 'hib', signatory_name: signatoryData.name_signatory_hib, signatory_title: signatoryData.title_signatory_hib, signatory_email: signatoryData.email_signatory_hib },
        { role_type: 'dpe', signatory_name: signatoryData.name_signatory_dpe, signatory_title: signatoryData.title_signatory_dpe, signatory_email: signatoryData.email_signatory_dpe },
        { role_type: 'dpo', signatory_name: signatoryData.dpo_name, signatory_title: '', signatory_email: signatoryData.dpo_email },
        { role_type: 'iso', signatory_name: signatoryData.iso_name, signatory_title: '', signatory_email: signatoryData.iso_email },
        { role_type: 'head_it', signatory_name: signatoryData.head_it_name, signatory_title: '', signatory_email: signatoryData.head_it_email },
        { role_type: 'it_manager', signatory_name: signatoryData.it_manager_name, signatory_title: '', signatory_email: signatoryData.it_manager_email }
      ];

      for (const update of updates) {
        const { error: sigError } = await supabaseClient
          .from('org_sig_roles')
          .upsert(update, { onConflict: 'role_type' });

        if (sigError) throw sigError;
      }

      toast.success('Organisation profile updated successfully');
      setIsEditing(false);
    } catch (error) {
      console.error('Error saving organisation data:', error);
      toast.error('Failed to save organisation data');
    } finally {
      setSaving(false);
    }
  };

  const fetchUserEmailAndRole = async (userId: string) => {
    try {
      // Get email using the database function
      const { data: emailData, error: emailError } = await supabaseClient
        .rpc('get_user_email_by_id', { user_id: userId });
      
      if (emailError) {
        console.error('Error fetching user email:', emailError);
        return { email: '', title: '' };
      }
      
      // Get primary role from user_profile_roles + roles
      const { data: roleData, error: roleError } = await supabaseClient
        .from('user_profile_roles')
        .select(`
          roles(name)
        `)
        .eq('user_id', userId)
        .eq('is_primary', true)
        .maybeSingle();
      
      if (roleError) {
        console.error('Error fetching user role:', roleError);
        return { email: emailData || '', title: '' };
      }
      
      return {
        email: emailData || '',
        title: (roleData?.roles as any)?.name || ''
      };
      
    } catch (error) {
      console.error('Error in fetchUserEmailAndRole:', error);
      return { email: '', title: '' };
    }
  };

  const handleProfileSelect = async (role: string, profile: Profile | null) => {
    if (!profile) {
      // Clear the selection
      switch (role) {
        case 'cem':
          setSignatoryData(prev => ({ 
            ...prev, 
            name_signatory_cem: '', 
            title_signatory_cem: '',
            email_signatory_cem: '' 
          }));
          break;
        case 'hib':
          setSignatoryData(prev => ({ 
            ...prev, 
            name_signatory_hib: '', 
            title_signatory_hib: '',
            email_signatory_hib: '' 
          }));
          break;
        case 'dpe':
          setSignatoryData(prev => ({ 
            ...prev, 
            name_signatory_dpe: '', 
            title_signatory_dpe: '',
            email_signatory_dpe: '' 
          }));
          break;
        case 'dpo':
          setSignatoryData(prev => ({ 
            ...prev, 
            dpo_name: '', 
            dpo_email: '' 
          }));
          break;
        case 'iso':
          setSignatoryData(prev => ({ 
            ...prev, 
            iso_name: '', 
            iso_email: '' 
          }));
          break;
        case 'head_it':
          setSignatoryData(prev => ({ 
            ...prev, 
            head_it_name: '', 
            head_it_email: '' 
          }));
          break;
        case 'it_manager':
          setSignatoryData(prev => ({ 
            ...prev, 
            it_manager_name: '', 
            it_manager_email: '' 
          }));
          break;
      }
      return;
    }

    // Get user's email and primary role
    const { email, title } = await fetchUserEmailAndRole(profile.id);
    
    switch (role) {
      case 'cem':
        setSignatoryData(prev => ({ 
          ...prev, 
          name_signatory_cem: profile.full_name, 
          title_signatory_cem: title,
          email_signatory_cem: email 
        }));
        break;
      case 'hib':
        setSignatoryData(prev => ({ 
          ...prev, 
          name_signatory_hib: profile.full_name, 
          title_signatory_hib: title,
          email_signatory_hib: email 
        }));
        break;
      case 'dpe':
        setSignatoryData(prev => ({ 
          ...prev, 
          name_signatory_dpe: profile.full_name, 
          title_signatory_dpe: title,
          email_signatory_dpe: email 
        }));
        break;
      case 'dpo':
        setSignatoryData(prev => ({ 
          ...prev, 
          dpo_name: profile.full_name, 
          dpo_email: email 
        }));
        break;
      case 'iso':
        setSignatoryData(prev => ({ 
          ...prev, 
          iso_name: profile.full_name, 
          iso_email: email 
        }));
        break;
      case 'head_it':
        setSignatoryData(prev => ({ 
          ...prev, 
          head_it_name: profile.full_name, 
          head_it_email: email 
        }));
        break;
      case 'it_manager':
        setSignatoryData(prev => ({ 
          ...prev, 
          it_manager_name: profile.full_name, 
          it_manager_email: email 
        }));
        break;
    }
  };

  const handleMfaToggle = (enabled: boolean) => {
    debug.log('[OrganisationProfile.handleMfaToggle] toggled', { enabled, hasAdminAccess });
    if (!enabled) {
      setShowDisableMfaConfirm(true);
      return;
    }
    applyMfaChange(true);
  };

  const applyMfaChange = async (enabled: boolean) => {
    setShowDisableMfaConfirm(false);
    setMfaSaving(true);
    try {
      const orgId = organisationData.id;
      let error;
      if (orgId) {
        ({ error } = await supabaseClient
          .from('org_profile')
          .update({ require_mfa: enabled })
          .eq('id', orgId));
      } else {
        const { data: inserted, error: insertError } = await supabaseClient
          .from('org_profile')
          .insert({ require_mfa: enabled })
          .select('id')
          .single();
        error = insertError;
        if (inserted) setOrganisationData(prev => ({ ...prev, id: inserted.id }));
      }

      if (error) throw error;
      setRequireMfa(enabled);

      if (!enabled) {
        try {
          const { data: { session } } = await supabaseClient.auth.getSession();
          const res = await supabaseClient.functions.invoke('reset-user-mfa', {
            body: {},
            headers: session?.access_token
              ? { Authorization: `Bearer ${session.access_token}` }
              : undefined,
          });
          if (res.error || !res.data?.success) {
            console.error('Bulk MFA reset warning:', res.error ?? res.data?.error);
            toast.warning('MFA requirement disabled, but some enrolled users may still be challenged until they log out.');
          } else {
            toast.success(res.data.message);
          }
        } catch (fnErr: any) {
          console.error('Bulk MFA reset error:', fnErr);
          toast.warning('MFA requirement disabled. Note: existing enrolled users may need a manual reset.');
        }
      } else {
        toast.success('MFA required for all users. They will be prompted on next login.');
      }
    } catch (err: any) {
      console.error('MFA toggle error:', err);
      toast.error('Failed to update MFA setting: ' + (err.message ?? 'unknown error'));
    } finally {
      setMfaSaving(false);
    }
  };

  const handleEntraToggle = async (enabled: boolean) => {
    setEntraSaving(true);
    try {
      const orgId = organisationData.id;
      let error;
      if (orgId) {
        ({ error } = await supabaseClient
          .from('org_profile')
          .update({ entra_enabled: enabled })
          .eq('id', orgId));
      } else {
        const { data: inserted, error: insertError } = await supabaseClient
          .from('org_profile')
          .insert({ entra_enabled: enabled })
          .select('id')
          .single();
        error = insertError;
        if (inserted) setOrganisationData(prev => ({ ...prev, id: inserted.id }));
      }
      if (error) throw error;
      setEntraEnabled(enabled);
      setOrganisationData(prev => ({ ...prev, entra_enabled: enabled }));
      toast.success(enabled ? 'Microsoft SSO enabled.' : 'Microsoft SSO disabled.');
    } catch (err: any) {
      console.error('Entra toggle error:', err);
      toast.error('Failed to update SSO setting: ' + (err.message ?? 'unknown error'));
    } finally {
      setEntraSaving(false);
    }
  };

  const handleDeviceToggle = async (enabled: boolean) => {
    setDeviceSaving(true);
    try {
      const orgId = organisationData.id;
      const newSource = enabled ? (organisationData.device_source || 'intune') : null;
      if (orgId) {
        const { error } = await supabaseClient
          .from('org_profile')
          .update({ device_source: newSource })
          .eq('id', orgId);
        if (error) throw error;
      } else {
        const { data: inserted, error: insertError } = await supabaseClient
          .from('org_profile')
          .insert({ device_source: newSource })
          .select('id')
          .single();
        if (insertError) throw insertError;
        if (inserted) setOrganisationData(prev => ({ ...prev, id: inserted.id }));
      }
      setDeviceEnabled(enabled);
      setOrganisationData(prev => ({ ...prev, device_source: newSource }));
      toast.success(enabled ? 'Device management enabled.' : 'Device management disabled.');
    } catch (err: any) {
      console.error('Device toggle error:', err);
      toast.error('Failed to update device management setting: ' + (err.message ?? 'unknown error'));
    } finally {
      setDeviceSaving(false);
    }
  };

  const handleSaveDeviceCredentials = async () => {
    try {
      setSaving(true);
      const orgId = organisationData.id;
      if (!orgId) { toast.error('Save organisation profile first.'); return; }

      const updates: Record<string, unknown> = {
        device_source: organisationData.device_source,
        intune_client_id: organisationData.intune_client_id ?? null,
        atera_customer_id: organisationData.atera_customer_id ?? null,
      };

      // Vault: only write secret if user typed a new value (not the placeholder)
      if (organisationData.device_source === 'intune' && intuneSecretDraft && intuneSecretDraft !== SECRET_PLACEHOLDER) {
        await supabaseClient.rpc('upsert_vault_secret', {
          secret_name: 'intune-client-secret',
          secret_value: intuneSecretDraft,
        });
        updates.intune_client_secret = 'intune-client-secret';
        setIntuneSecretDraft(SECRET_PLACEHOLDER);
      }
      if (organisationData.device_source === 'atera' && ateraKeyDraft && ateraKeyDraft !== SECRET_PLACEHOLDER) {
        await supabaseClient.rpc('upsert_vault_secret', {
          secret_name: 'atera-api-key',
          secret_value: ateraKeyDraft,
        });
        updates.atera_api_key = 'atera-api-key';
        setAteraKeyDraft(SECRET_PLACEHOLDER);
      }

      const { error } = await supabaseClient.from('org_profile').update(updates).eq('id', orgId);
      if (error) throw error;
      setOrganisationData(prev => ({ ...prev, ...updates }));
      toast.success('Device management settings saved.');
    } catch (err: any) {
      console.error('Device credentials save error:', err);
      toast.error('Failed to save device settings: ' + (err.message ?? 'unknown error'));
    } finally {
      setSaving(false);
    }
  };

  const handleTestConnection = async () => {
    setTestingConnection(true);
    try {
      // Use functions.invoke so the client's configured URL is used (avoids VITE_SUPABASE_URL dependency).
      // dry_run is passed in the body; the edge function reads it from either query string or body.
      const { data, error } = await (supabaseClient as any).functions.invoke('device-ingest/v1/sync', {
        method: 'POST',
        body: { dry_run: true },
      });
      if (error || !data?.success) {
        toast.error(`Connection test failed: ${data?.error ?? error?.message ?? 'unknown error'}`);
      } else {
        toast.success(`Connection successful — ${data.synced_count} device(s) found via ${data.source}.`);
      }
    } catch (err: any) {
      toast.error('Connection test error: ' + (err.message ?? 'unknown error'));
    } finally {
      setTestingConnection(false);
    }
  };

  const handleCancel = () => {
    setIsEditing(false);
    fetchOrganisationData(); // Reset to original data
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center p-8">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6 text-left">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold">Organisation Profile</h2>
          <p className="text-muted-foreground">Manage organisation details and signatory information</p>
        </div>
        {!isEditing ? (
          <Button onClick={() => setIsEditing(true)} variant="outline" size="icon">
            <Edit className="h-4 w-4" />
          </Button>
        ) : (
          <div className="flex gap-2">
            <Button onClick={handleSave} disabled={saving} size="icon">
              <Save className="h-4 w-4" />
            </Button>
            <Button onClick={handleCancel} variant="outline" disabled={saving} size="icon">
              <X className="h-4 w-4" />
            </Button>
          </div>
        )}
      </div>

      {/* General Organisation Information */}
      <Card>
        <CardHeader>
          <CardTitle>General Information</CardTitle>
        </CardHeader>
        <CardContent className="space-y-4 text-left">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="org-name">Organisation Name</Label>
              <Input
                id="org-name"
                value={organisationData.org_name || ''}
                onChange={(e) => setOrganisationData(prev => ({ ...prev, org_name: e.target.value }))}
                disabled={!isEditing}
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="org-name-short">Organisation Name (Short)</Label>
              <Input
                id="org-name-short"
                value={organisationData.org_short_name || ''}
                onChange={(e) => setOrganisationData(prev => ({ ...prev, org_short_name: e.target.value }))}
                disabled={!isEditing || !isSuperAdmin}
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="acra-uen">ACRA Number/Unique Entity Number (UEN)</Label>
              <Input
                id="acra-uen"
                value={organisationData.acra_uen_number || ''}
                onChange={(e) => setOrganisationData(prev => ({ ...prev, acra_uen_number: e.target.value }))}
                disabled={!isEditing}
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="charity-reg">Charity Registration Number</Label>
              <Input
                id="charity-reg"
                value={organisationData.charity_registration_number || ''}
                onChange={(e) => setOrganisationData(prev => ({ ...prev, charity_registration_number: e.target.value }))}
                disabled={!isEditing}
              />
            </div>
          </div>
          
          <div className="space-y-2">
            <Label htmlFor="address">Address</Label>
            <Textarea
              id="address"
              value={organisationData.address || ''}
              onChange={(e) => setOrganisationData(prev => ({ ...prev, address: e.target.value }))}
              disabled={!isEditing}
              rows={3}
            />
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="telephone">Telephone</Label>
              <Input
                id="telephone"
                value={organisationData.telephone || ''}
                onChange={handleTelephoneChange} // Use the new handler
                disabled={!isEditing}
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="annual-turnover">Annual Turnover</Label>
              <Input
                id="annual-turnover"
                value={organisationData.annual_turnover || ''}
                onChange={(e) => setOrganisationData(prev => ({ ...prev, annual_turnover: e.target.value }))}
                disabled={!isEditing}
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="num-employees">Number of Employees</Label>
              <Input
                id="num-employees"
                type="number"
                value={organisationData.number_of_employees || ''}
                onChange={(e) => setOrganisationData(prev => ({ ...prev, number_of_employees: parseInt(e.target.value) || 0 }))}
                disabled={!isEditing}
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="num-executives">Number of Executives</Label>
              <Input
                id="num-executives"
                type="number"
                value={organisationData.number_of_executives || ''}
                onChange={(e) => setOrganisationData(prev => ({ ...prev, number_of_executives: parseInt(e.target.value) || 0 }))}
                disabled={!isEditing}
              />
            </div>
          </div>

          <div className="space-y-2">
            <Label htmlFor="cert-body">Appointed Certification Body</Label>
            <Input
              id="cert-body"
              value={organisationData.appointed_certification_body || ''}
              onChange={(e) => setOrganisationData(prev => ({ ...prev, appointed_certification_body: e.target.value }))}
              disabled={!isEditing}
            />
          </div>

          <Separator />

          {/* Organisation Logo */}
          <div className="space-y-3">
            <Label>Organisation Logo</Label>
            <p className="text-xs text-muted-foreground">
              Used on generated certificates alongside the RAYN logo. Recommended: transparent PNG or SVG, max 2 MB.
            </p>

            {organisationData.org_logo_url && (
              <div className="flex items-center gap-3">
                <img
                  src={organisationData.org_logo_url}
                  alt="Organisation logo"
                  className="h-14 max-w-[160px] object-contain border rounded p-1 bg-muted"
                />
                {isEditing && (
                  <Button
                    type="button"
                    variant="ghost"
                    size="sm"
                    onClick={() => setOrganisationData(prev => ({ ...prev, org_logo_url: '' }))}
                  >
                    <X className="h-4 w-4 mr-1" /> Remove
                  </Button>
                )}
              </div>
            )}

            {isEditing && (
              <div className="flex items-center gap-3">
                <div className="space-y-1 flex-1">
                  <Input
                    placeholder="https://... (paste a URL, or upload a file below)"
                    value={organisationData.org_logo_url || ''}
                    onChange={(e) => setOrganisationData(prev => ({ ...prev, org_logo_url: e.target.value }))}
                  />
                </div>
                <span className="text-xs text-muted-foreground">or</span>
                <Button
                  type="button"
                  variant="outline"
                  size="sm"
                  disabled={uploadingLogo}
                  onClick={() => logoFileInputRef.current?.click()}
                >
                  {uploadingLogo ? (
                    <Loader2 className="h-4 w-4 animate-spin mr-1" />
                  ) : (
                    <Upload className="h-4 w-4 mr-1" />
                  )}
                  Upload
                </Button>
                <input
                  ref={logoFileInputRef}
                  type="file"
                  accept="image/jpeg,image/png,image/gif,image/webp,image/svg+xml"
                  className="hidden"
                  onChange={handleLogoUpload}
                />
              </div>
            )}

            {!organisationData.org_logo_url && !isEditing && (
              <div className="flex items-center gap-2 text-muted-foreground text-sm">
                <ImageIcon className="h-4 w-4" />
                <span>No logo uploaded</span>
              </div>
            )}
          </div>
        </CardContent>
      </Card>

      {/* Sign In & Devices */}
      {hasAdminAccess && (
        <Card>
          <CardHeader>
            <CardTitle>Sign In &amp; Devices</CardTitle>
          </CardHeader>
          <CardContent className="space-y-6">

            {/* Require MFA */}
            <div className="flex items-center justify-between">
              <div className="space-y-1">
                <div className="flex items-center gap-2">
                  {requireMfa
                    ? <ShieldCheck className="h-4 w-4 text-primary" />
                    : <Shield className="h-4 w-4 text-muted-foreground" />
                  }
                  <Label htmlFor="require-mfa-toggle" className="text-sm font-medium cursor-pointer">
                    Require MFA
                  </Label>
                </div>
                <p className="text-xs text-muted-foreground pl-6">
                  Users must enrol an authenticator app before accessing the platform. Admins always require MFA regardless of this setting.
                </p>
              </div>
              <Switch
                id="require-mfa-toggle"
                checked={requireMfa}
                onCheckedChange={handleMfaToggle}
                disabled={mfaSaving}
                aria-label="Require MFA for all users"
              />
            </div>

            <Separator />

            {/* Microsoft Entra SSO */}
            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <div className="space-y-1">
                  <Label htmlFor="entra-toggle" className="text-sm font-medium cursor-pointer">
                    Sign in with Microsoft
                  </Label>
                  <p className="text-xs text-muted-foreground">
                    Show the "Sign in with Microsoft" button on the login page. Requires a Directory (tenant) ID.
                  </p>
                </div>
                <Switch
                  id="entra-toggle"
                  checked={entraEnabled}
                  onCheckedChange={handleEntraToggle}
                  disabled={entraSaving || (!organisationData.azure_tenant_id && !entraEnabled)}
                  aria-label="Enable Microsoft SSO"
                />
              </div>

              <div className="space-y-2">
                <Label htmlFor="azure-tenant-id" className="text-sm">
                  Directory (tenant) ID
                </Label>
                <Input
                  id="azure-tenant-id"
                  placeholder="xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx"
                  value={organisationData.azure_tenant_id || ''}
                  onChange={(e) => setOrganisationData(prev => ({ ...prev, azure_tenant_id: e.target.value }))}
                  disabled={!isEditing || !isSuperAdmin}
                  className="font-mono text-sm"
                />
                {!isSuperAdmin && (
                  <p className="text-xs text-muted-foreground">Contact your RAYN administrator to update the tenant ID.</p>
                )}
              </div>
            </div>

            {/* Device Management — Govern only */}
            {!isLearnMode && (
              <>
                <Separator />

                <div className="space-y-4">
                  <div className="flex items-center justify-between">
                    <div className="space-y-1">
                      <div className="flex items-center gap-2">
                        <MonitorSmartphone className="h-4 w-4 text-muted-foreground" />
                        <Label htmlFor="device-toggle" className="text-sm font-medium cursor-pointer">
                          Device Management
                        </Label>
                      </div>
                      <p className="text-xs text-muted-foreground pl-6">
                        Sync devices from Intune or Atera into the hardware inventory.
                      </p>
                    </div>
                    <Switch
                      id="device-toggle"
                      checked={deviceEnabled}
                      onCheckedChange={handleDeviceToggle}
                      disabled={deviceSaving}
                      aria-label="Enable device management"
                    />
                  </div>

                  {deviceEnabled && (
                    <div className="space-y-4 pl-6">
                      {/* Source selector */}
                      <div className="space-y-2">
                        <Label className="text-sm">Source</Label>
                        <Select
                          value={organisationData.device_source ?? ''}
                          onValueChange={(val) => setOrganisationData(prev => ({ ...prev, device_source: val }))}
                          disabled={!isSuperAdmin}
                        >
                          <SelectTrigger className="w-48">
                            <SelectValue placeholder="Select source…" />
                          </SelectTrigger>
                          <SelectContent>
                            <SelectItem value="intune">Intune</SelectItem>
                            <SelectItem value="atera">Atera</SelectItem>
                          </SelectContent>
                        </Select>
                      </div>

                      {/* Intune fields */}
                      {organisationData.device_source === 'intune' && (
                        <div className="space-y-3">
                          <p className="text-xs text-muted-foreground">
                            Uses the Directory (tenant) ID above. Provide the app registration credentials below.
                          </p>
                          <div className="space-y-2">
                            <Label htmlFor="intune-client-id" className="text-sm">Application (client) ID</Label>
                            <Input
                              id="intune-client-id"
                              placeholder="xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx"
                              value={organisationData.intune_client_id || ''}
                              onChange={(e) => setOrganisationData(prev => ({ ...prev, intune_client_id: e.target.value }))}
                              disabled={!isSuperAdmin}
                              className="font-mono text-sm"
                            />
                          </div>
                          <div className="space-y-2">
                            <Label htmlFor="intune-client-secret" className="text-sm">Client Secret</Label>
                            <Input
                              id="intune-client-secret"
                              type="password"
                              placeholder={intuneSecretDraft || 'Enter client secret…'}
                              value={intuneSecretDraft === SECRET_PLACEHOLDER ? '' : intuneSecretDraft}
                              onFocus={() => { if (intuneSecretDraft === SECRET_PLACEHOLDER) setIntuneSecretDraft(''); }}
                              onBlur={() => { if (!intuneSecretDraft && organisationData.intune_client_secret) setIntuneSecretDraft(SECRET_PLACEHOLDER); }}
                              onChange={(e) => setIntuneSecretDraft(e.target.value)}
                              disabled={!isSuperAdmin}
                              className="font-mono text-sm"
                            />
                            {organisationData.intune_client_secret && (
                              <p className="text-xs text-muted-foreground">Secret is stored securely. Enter a new value to rotate it.</p>
                            )}
                          </div>
                        </div>
                      )}

                      {/* Atera fields */}
                      {organisationData.device_source === 'atera' && (
                        <div className="space-y-3">
                          <div className="space-y-2">
                            <Label htmlFor="atera-api-key" className="text-sm">API Key</Label>
                            <Input
                              id="atera-api-key"
                              type="password"
                              placeholder={ateraKeyDraft || 'Enter API key…'}
                              value={ateraKeyDraft === SECRET_PLACEHOLDER ? '' : ateraKeyDraft}
                              onFocus={() => { if (ateraKeyDraft === SECRET_PLACEHOLDER) setAteraKeyDraft(''); }}
                              onBlur={() => { if (!ateraKeyDraft && organisationData.atera_api_key) setAteraKeyDraft(SECRET_PLACEHOLDER); }}
                              onChange={(e) => setAteraKeyDraft(e.target.value)}
                              disabled={!isSuperAdmin}
                              className="font-mono text-sm"
                            />
                            {organisationData.atera_api_key && (
                              <p className="text-xs text-muted-foreground">Key is stored securely. Enter a new value to rotate it.</p>
                            )}
                          </div>
                          <div className="space-y-2">
                            <Label htmlFor="atera-customer-id" className="text-sm">Customer ID</Label>
                            <Input
                              id="atera-customer-id"
                              type="number"
                              placeholder="12345"
                              value={organisationData.atera_customer_id ?? ''}
                              onChange={(e) => setOrganisationData(prev => ({ ...prev, atera_customer_id: parseInt(e.target.value) || null }))}
                              disabled={!isSuperAdmin}
                              className="font-mono text-sm w-48"
                            />
                          </div>
                        </div>
                      )}

                      {/* Save + Test connection */}
                      {organisationData.device_source && isSuperAdmin && (
                        <div className="flex items-center gap-3 pt-1">
                          <Button
                            size="sm"
                            onClick={handleSaveDeviceCredentials}
                            disabled={saving}
                          >
                            {saving ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : null}
                            Save credentials
                          </Button>
                          <Button
                            size="sm"
                            variant="outline"
                            onClick={handleTestConnection}
                            disabled={testingConnection}
                          >
                            {testingConnection
                              ? <Loader2 className="h-4 w-4 animate-spin mr-2" />
                              : <FlaskConical className="h-4 w-4 mr-2" />
                            }
                            Test connection
                          </Button>
                          {organisationData.device_last_synced_at && (
                            <span className="text-xs text-muted-foreground">
                              Last synced: {new Date(organisationData.device_last_synced_at).toLocaleString()}
                            </span>
                          )}
                        </div>
                      )}
                    </div>
                  )}
                </div>
              </>
            )}

          </CardContent>
        </Card>
      )}

      {/* Key People & Compliance */}
      <Card>
        <CardHeader>
          <CardTitle>Key People &amp; Compliance</CardTitle>
        </CardHeader>
        <CardContent className="space-y-6 text-left">

          {/* Key Personnel — shown in all modes */}
          <div className="space-y-4">
            <h4 className="font-semibold text-sm text-muted-foreground uppercase tracking-wide">Key Personnel</h4>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="dpo-name">DPO Name</Label>
                <SearchableProfileField
                  value={signatoryData.dpo_name}
                  onSelect={(profile) => handleProfileSelect('dpo', profile)}
                  placeholder="Select DPO..."
                  disabled={!isEditing}
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="dpo-email">DPO Email</Label>
                <Input
                  id="dpo-email"
                  type="email"
                  value={signatoryData.dpo_email || ''}
                  onChange={(e) => setSignatoryData(prev => ({ ...prev, dpo_email: e.target.value }))}
                  disabled={!isEditing}
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="iso-name">ISO Name</Label>
                <SearchableProfileField
                  value={signatoryData.iso_name}
                  onSelect={(profile) => handleProfileSelect('iso', profile)}
                  placeholder="Select ISO..."
                  disabled={!isEditing}
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="iso-email">ISO Email</Label>
                <Input
                  id="iso-email"
                  type="email"
                  value={signatoryData.iso_email || ''}
                  onChange={(e) => setSignatoryData(prev => ({ ...prev, iso_email: e.target.value }))}
                  disabled={!isEditing}
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="head-it-name">Head of IT Name</Label>
                <SearchableProfileField
                  value={signatoryData.head_it_name}
                  onSelect={(profile) => handleProfileSelect('head_it', profile)}
                  placeholder="Select Head of IT..."
                  disabled={!isEditing}
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="head-it-email">Head of IT Email</Label>
                <Input
                  id="head-it-email"
                  type="email"
                  value={signatoryData.head_it_email || ''}
                  onChange={(e) => setSignatoryData(prev => ({ ...prev, head_it_email: e.target.value }))}
                  disabled={!isEditing}
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="it-manager-name">IT Manager Name</Label>
                <SearchableProfileField
                  value={signatoryData.it_manager_name}
                  onSelect={(profile) => handleProfileSelect('it_manager', profile)}
                  placeholder="Select IT Manager..."
                  disabled={!isEditing}
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="it-manager-email">IT Manager Email</Label>
                <Input
                  id="it-manager-email"
                  type="email"
                  value={signatoryData.it_manager_email || ''}
                  onChange={(e) => setSignatoryData(prev => ({ ...prev, it_manager_email: e.target.value }))}
                  disabled={!isEditing}
                />
              </div>
            </div>
          </div>

          {/* Signatory sections — Govern / compliance only */}
          {!isLearnMode && (
            <>
              <Separator />

              {/* CEM Declaration Signatory */}
              <div className="space-y-4">
                <h4 className="font-semibold text-sm text-muted-foreground uppercase tracking-wide">CEM Declaration</h4>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  <div className="space-y-2">
                    <Label htmlFor="cem-name">Name of Signatory to CEM Declaration</Label>
                    <SearchableProfileField
                      value={signatoryData.name_signatory_cem}
                      onSelect={(profile) => handleProfileSelect('cem', profile)}
                      placeholder="Select CEM signatory..."
                      disabled={!isEditing}
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="cem-title">Title of Signatory to CEM Declaration</Label>
                    <Input
                      id="cem-title"
                      value={signatoryData.title_signatory_cem || ''}
                      onChange={(e) => setSignatoryData(prev => ({ ...prev, title_signatory_cem: e.target.value }))}
                      disabled={!isEditing}
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="cem-email">Email of Signatory to CEM Declaration</Label>
                    <Input
                      id="cem-email"
                      type="email"
                      value={signatoryData.email_signatory_cem || ''}
                      onChange={(e) => setSignatoryData(prev => ({ ...prev, email_signatory_cem: e.target.value }))}
                      disabled={!isEditing}
                    />
                  </div>
                </div>
              </div>

              <Separator />

              {/* HIB Pledge Signatory */}
              <div className="space-y-4">
                <h4 className="font-semibold text-sm text-muted-foreground uppercase tracking-wide">HIB Pledge</h4>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  <div className="space-y-2">
                    <Label htmlFor="hib-name">Name of Signatory to HIB Pledge</Label>
                    <SearchableProfileField
                      value={signatoryData.name_signatory_hib}
                      onSelect={(profile) => handleProfileSelect('hib', profile)}
                      placeholder="Select HIB signatory..."
                      disabled={!isEditing}
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="hib-title">Title of Signatory to HIB Pledge</Label>
                    <Input
                      id="hib-title"
                      value={signatoryData.title_signatory_hib || ''}
                      onChange={(e) => setSignatoryData(prev => ({ ...prev, title_signatory_hib: e.target.value }))}
                      disabled={!isEditing}
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="hib-email">Email of Signatory to HIB Pledge</Label>
                    <Input
                      id="hib-email"
                      type="email"
                      value={signatoryData.email_signatory_hib || ''}
                      onChange={(e) => setSignatoryData(prev => ({ ...prev, email_signatory_hib: e.target.value }))}
                      disabled={!isEditing}
                    />
                  </div>
                </div>
              </div>

              <Separator />

              {/* DPE Pledge Signatory */}
              <div className="space-y-4">
                <h4 className="font-semibold text-sm text-muted-foreground uppercase tracking-wide">DPE Pledge</h4>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  <div className="space-y-2">
                    <Label htmlFor="dpe-name">Name of Signatory to DPE Pledge</Label>
                    <SearchableProfileField
                      value={signatoryData.name_signatory_dpe}
                      onSelect={(profile) => handleProfileSelect('dpe', profile)}
                      placeholder="Select DPE signatory..."
                      disabled={!isEditing}
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="dpe-title">Title of Signatory to DPE Pledge</Label>
                    <Input
                      id="dpe-title"
                      value={signatoryData.title_signatory_dpe || ''}
                      onChange={(e) => setSignatoryData(prev => ({ ...prev, title_signatory_dpe: e.target.value }))}
                      disabled={!isEditing}
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="dpe-email">Email of Signatory to DPE Pledge</Label>
                    <Input
                      id="dpe-email"
                      type="email"
                      value={signatoryData.email_signatory_dpe || ''}
                      onChange={(e) => setSignatoryData(prev => ({ ...prev, email_signatory_dpe: e.target.value }))}
                      disabled={!isEditing}
                    />
                  </div>
                </div>
              </div>
            </>
          )}

        </CardContent>
      </Card>
      <AlertDialog open={showDisableMfaConfirm} onOpenChange={setShowDisableMfaConfirm}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Disable MFA requirement?</AlertDialogTitle>
            <AlertDialogDescription>
              This will remove the MFA requirement for all non-admin users and
              automatically unenrol anyone who has already set it up. Admin
              accounts will still require MFA regardless of this setting.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction onClick={() => applyMfaChange(false)}>
              Disable &amp; unenrol users
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
};

export default OrganisationProfile;
